from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Identify the main subject (typically an airport based on key predicates)
    main_subject = None
    airport_indicators = {"cityServed", "location", "runwayLength", "icaoLocationIdentifier", "iataLocationIdentifier"}
    for subject, triples_list in subject_map.items():
        if any(predicate in airport_indicators for predicate, _ in triples_list):
            main_subject = subject
            break

    if not main_subject:
        main_subject = next(iter(subject_map.keys()))  # Fallback to first subject

    sentence = main_subject
    added_properties = set()

    # Process properties of the main subject
    for predicate, obj in subject_map[main_subject]:
        if predicate == "cityServed":
            sentence += f" serves the city of {obj}"
            added_properties.add("cityServed")
        elif predicate == "location":
            sentence += f" is located in {obj}"
            added_properties.add("location")
        elif predicate == "operatingOrganisation":
            sentence += f" is operated by {obj}"
            added_properties.add("operatingOrganisation")
        elif predicate == "elevationAboveTheSeaLevel":
            sentence += f" has an elevation of {obj} metres above sea level"
            added_properties.add("elevationAboveTheSeaLevel")
        elif predicate == "runwayLength":
            sentence += f" has a runway length of {obj} metres"
            added_properties.add("runwayLength")
        elif predicate == "icaoLocationIdentifier":
            sentence += f" has an ICAO location identifier of {obj}"
            added_properties.add("icaoLocationIdentifier")
        elif predicate == "iataLocationIdentifier":
            sentence += f" has an IATA location identifier of {obj}"
            added_properties.add("iataLocationIdentifier")
        elif predicate == "elevationAboveTheSeaLevelInFeet":
            sentence += f" has an elevation of {obj} feet above sea level"
            added_properties.add("elevationAboveTheSeaLevelInFeet")
        elif predicate == "nativeName":
            sentence += f" is also known as {obj}"
            added_properties.add("nativeName")
        elif predicate == "owner":
            sentence += f" is owned by {obj}"
            added_properties.add("owner")
        elif predicate == "1stRunwayLengthFeet":
            sentence += f" has a first runway that is {obj} feet long"
            added_properties.add("1stRunwayLengthFeet")
        elif predicate == "1stRunwaySurfaceType":
            sentence += f" has a first runway with surface type {obj}"
            added_properties.add("1stRunwaySurfaceType")
        elif predicate == "3rdRunwayLengthFeet":
            sentence += f" has a third runway that is {obj} feet long"
            added_properties.add("3rdRunwayLengthFeet")
        elif predicate == "4thRunwayLengthFeet":
            sentence += f" has a fourth runway that is {obj} feet long"
            added_properties.add("4thRunwayLengthFeet")
        elif predicate == "4thRunwaySurfaceType":
            sentence += f" has a fourth runway with surface type {obj}"
            added_properties.add("4thRunwaySurfaceType")
        elif predicate == "5thRunwayNumber":
            sentence += f" has a fifth runway numbered {obj}"
            added_properties.add("5thRunwayNumber")
        elif predicate == "5thRunwaySurfaceType":
            sentence += f" has a fifth runway with surface type {obj}"
            added_properties.add("5thRunwaySurfaceType")

    # Connect related entities (country, capital, language, mayor, etc.) using other subjects
    for subject, triples_list in subject_map.items():
        if subject == main_subject:
            continue

        for predicate, obj in triples_list:
            if predicate == "country" and "cityServed" in added_properties:
                city_served = next((o for p, o in subject_map[main_subject] if p == "cityServed"), None)
                if city_served:
                    sentence += f", which is in {obj}"
            elif predicate == "capital":
                sentence += f", whose capital is {obj}"
            elif predicate == "officialLanguage":
                sentence += f" and its official language is {obj}"
            elif predicate == "mayor" and "cityServed" in added_properties:
                city_served = next((o for p, o in subject_map[main_subject] if p == "cityServed"), None)
                if city_served:
                    sentence += f", where the mayor is {obj}"
            elif predicate == "language" and "cityServed" in added_properties:
                city_served = next((o for p, o in subject_map[main_subject] if p == "cityServed"), None)
                if city_served:
                    sentence += f", and the city speaks {obj}"
            elif predicate == "isPartOf":
                sentence += f", which is part of {obj}"
            elif predicate == "leader":
                sentence += f", led by {obj}"
            elif predicate == "leaderParty":
                sentence += f", with leader party {obj}"

    # Clean up extra spaces and ensure proper punctuation
    sentence = " ".join(sentence.split())  # Normalize whitespace
    if not sentence.endswith("."):
        sentence += "."

    return sentence
